proof fn phi_1_prefix_secure_external_body_trait<C: SecureSpecCombinator>(c: &C, s1: Seq<u8>, s2: Seq<u8>)
    requires
        c.requires(),
        C::is_prefix_secure(),
        c.spec_parse(s1).is_some(),
    ensures
        c.spec_parse(s1 + s2) == c.spec_parse(s1),
{
    c.lemma_prefix_secure(s1, s2);
}

proof fn phi_2_repeatn_prefix_secure_external_body<C: SecureSpecCombinator>(c: &RepeatN<C>, s1: Seq<u8>, s2: Seq<u8>)
    requires
        c.requires(),
        RepeatN::<C>::is_prefix_secure(),
        c.spec_parse(s1).is_some(),
    ensures
        c.spec_parse(s1 + s2) == c.spec_parse(s1),
{
    c.lemma_prefix_secure(s1, s2);
}

proof fn phi_3_parse_length_helper_external_body<C: SecureSpecCombinator>(c: &RepeatN<C>, s: Seq<u8>, n: usize, m: int, vs: Seq<C::Type>)
    requires
        c.requires(),
        c.spec_parse_helper(s, n) == Some((m, vs)),
    ensures
        0 <= m <= s.len(),
{
    c.lemma_parse_length_helper(s, n);
}

proof fn phi_5_prefix_secure_helper_verified_but_unused<C: SecureSpecCombinator>(c: &RepeatN<C>, s1: Seq<u8>, s2: Seq<u8>)
    requires
        c.requires(),
        c.spec_parse_helper(s1, c.1).is_some(),
    ensures
        c.spec_parse_helper(s1 + s2, c.1) == c.spec_parse_helper(s1, c.1),
{
    c.lemma_prefix_secure_helper(s1, s2, c.1);
}
